// Analytics Aggregator: Calculate Hiring Funnel Metrics
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // Calculate processing time
  const received = new Date(data.receivedDate);
  const processed = new Date(data.analysisTimestamp);
  const processingTimeSeconds = (processed - received) / 1000;

  // Determine outcome
  const outcome = data.qualified ? 'Accepted' : 'Rejected';

  // Calculate skill match percentage
  const totalPossibleSkills = 45; // Sum of all skill categories
  const skillMatchPercentage = ((data.totalSkills / totalPossibleSkills) * 100).toFixed(1);

  results.push({
    json: {
      ...data,
      analytics: {
        outcome: outcome,
        processingTimeSeconds: processingTimeSeconds.toFixed(2),
        skillMatchPercentage: skillMatchPercentage,
        hasLinkedIn: data.candidateLinkedIn !== 'Not Found',
        hasCertifications: data.certifications.length > 0,
        degreeLevel: data.highestDegree,
        experienceLevel: data.yearsExperience >= 7 ? 'Senior' : 
                        data.yearsExperience >= 3 ? 'Mid-Level' : 'Junior',
        timestamp: new Date().toISOString()
      }
    }
  });
}

return results;
